```cpp
void InputManager::DispatchEvent(const std::shared_ptr<Event>& event) {
    // Attempt to dynamically cast to a GamepadButtonDownEvent
    auto* gamepadButtonDownEvent = dynamic_cast<GamepadButtonDownEvent*>(event.get());
